/**
 * Incremental Email Fetch CLI (T042a)
 *
 * Wires together Gmail API integration (T037), email fetching (T038b),
 * and Prisma persistence (T042) to fetch and persist new emails since
 * the last recorded timestamp in the database.
 *
 * Usage:
 *   npm run fetch:emails                    # Fetch since last DB timestamp
 *   npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
 */

import { GmailClient } from '../gmail/gmail-client';
import { EmailFetcher } from '../gmail/email-fetcher';
import { EmailRepository } from '../persistence/email-repository';

/**
 * Options for fetchAndPersistEmails function
 */
export interface FetchAndPersistOptions {
  gmailClient: GmailClient;
  emailFetcher: EmailFetcher;
  repository: EmailRepository;
  sinceDate?: Date; // Optional: Override last DB timestamp
}

/**
 * Error details for fetch/persist operations
 */
export interface FetchError {
  type: 'authentication' | 'fetch' | 'persistence';
  message: string;
  originalError?: unknown;
}

/**
 * Result summary for fetch and persist operation
 */
export interface FetchAndPersistResult {
  success: boolean;
  fetchedCount: number;
  persistedCount: number;
  sinceTimestamp: Date | null;
  errors: FetchError[];
  startTime: Date;
  endTime: Date;
  durationMs: number;
}

/**
 * Fetch and persist new emails since last database timestamp
 *
 * This function implements the core logic for incremental email fetching:
 * 1. Query last email timestamp from database (unless sinceDate provided)
 * 2. Fetch new emails from Gmail API since that timestamp
 * 3. Persist emails using Prisma batch upsert
 * 4. Return detailed result summary with error handling
 *
 * @param options - Configuration for Gmail client, fetcher, and repository
 * @returns Result summary with counts, timestamps, and any errors
 *
 * @example
 * ```typescript
 * const result = await fetchAndPersistEmails({
 *   gmailClient: new GmailClient(auth),
 *   emailFetcher: new EmailFetcher(gmailClient),
 *   repository: new EmailRepository(),
 * });
 *
 * console.log(`Fetched ${result.fetchedCount} emails, persisted ${result.persistedCount}`);
 * ```
 */
export async function fetchAndPersistEmails(options: FetchAndPersistOptions): Promise<FetchAndPersistResult> {
  const { gmailClient, emailFetcher, repository, sinceDate } = options;

  const startTime = new Date();
  const result: FetchAndPersistResult = {
    success: false,
    fetchedCount: 0,
    persistedCount: 0,
    sinceTimestamp: null,
    errors: [],
    startTime,
    endTime: startTime, // Will be updated at end
    durationMs: 0,
  };

  try {
    // Step 1: Check Gmail authentication
    if (!gmailClient.isAuthenticated()) {
      result.errors.push({
        type: 'authentication',
        message: 'Gmail client is not authenticated. Please authenticate before fetching emails.',
      });
      return result;
    }

    // Step 2: Determine timestamp to fetch from
    let fetchSince: Date | null = null;

    if (sinceDate) {
      // Use custom date if provided
      fetchSince = sinceDate;
      result.sinceTimestamp = sinceDate;
    } else {
      // Query last email timestamp from database
      try {
        fetchSince = await repository.getLastEmailTimestamp();
        result.sinceTimestamp = fetchSince;
      } catch (error) {
        result.errors.push({
          type: 'persistence',
          message: `Failed to query last email timestamp: ${error instanceof Error ? error.message : String(error)}`,
          originalError: error,
        });
        return result;
      }
    }

    // Step 3: Fetch emails from Gmail API
    let emails;
    try {
      if (fetchSince) {
        // Fetch emails since timestamp
        emails = await emailFetcher.fetchEmailsSince(fetchSince);
      } else {
        // No previous emails, fetch all (with default limit)
        emails = await emailFetcher.fetchEmails({ limit: 100 });
      }

      result.fetchedCount = emails.length;
    } catch (error) {
      result.errors.push({
        type: 'fetch',
        message: `Failed to fetch emails from Gmail API: ${error instanceof Error ? error.message : String(error)}`,
        originalError: error,
      });
      return result;
    }

    // Step 4: Persist emails to database (if any were fetched)
    if (emails.length > 0) {
      try {
        await repository.batchInsert(emails);
        result.persistedCount = emails.length;
        result.success = true;
      } catch (error) {
        result.errors.push({
          type: 'persistence',
          message: `Failed to persist emails to database: ${error instanceof Error ? error.message : String(error)}`,
          originalError: error,
        });
        return result;
      }
    } else {
      // No new emails, but operation was successful
      result.success = true;
    }

    return result;
  } finally {
    // Update end time and duration
    result.endTime = new Date();
    result.durationMs = result.endTime.getTime() - result.startTime.getTime();
  }
}

/**
 * CLI entry point for fetch-emails command
 *
 * Parses command-line arguments and executes fetchAndPersistEmails.
 * Handles authentication, logging, and error reporting.
 *
 * @example
 * ```bash
 * npm run fetch:emails                        # Fetch since last DB timestamp
 * npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
 * ```
 */
export async function main(): Promise<void> {
  // TODO: Implement CLI argument parsing and initialization
  // This will be completed after core function is tested
  console.log('CLI entry point - to be implemented after TDD verification');
}

// Run CLI if executed directly
if (require.main === module) {
  main()
    .then(() => process.exit(0))
    .catch((error) => {
      console.error('Fatal error:', error);
      process.exit(1);
    });
}

