    let fetchSince: Date | null = null;

    if (sinceDate) {
      // Use custom date if provided
      fetchSince = sinceDate;
      result.sinceTimestamp = sinceDate;
    } else {
      // Query last email timestamp from database
      try {
        fetchSince = await repository.getLastEmailTimestamp();
        result.sinceTimestamp = fetchSince;
      } catch (error) {
        result.errors.push({
          type: 'persistence',
          message: `Failed to query last email timestamp: ${error instanceof Error ? error.message : String(error)}`,
          originalError: error,
        });
        return result;
      }
    }

