        emails.map((email) =>
          this.prisma.gmailMessage.upsert({
            where: { gmailId: email.id },
            create: this.emailToDb(email),
            update: this.emailToDb(email),
          })
        )
      );
    } catch (error) {
      throw new Error(
        `Failed to batch insert ${emails.length} emails: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

